+import { $internal } from '../common';
+import { destroyEntity, initializeDeferredEntity } from '../entity/entity';
+import type { Entity } from '../entity/types';
+import { allocateEntity, releaseEntity } from '../entity/utils/entity-index';
+import { getRelationTargets } from '../relation/relation';
+import type { RelationPair } from '../relation/types';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { addTrait, getTrait, hasTrait, removeTrait } from '../trait/trait';
+import type { ConfigurableTrait, Trait } from '../trait/types';
+import type { DeferredWorld, World } from './types';
+
+type Command =
+    | { type: 'spawn'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'destroy'; entity: Entity }
+    | { type: 'add'; entity: Entity; traits: ConfigurableTrait[] }
+    | { type: 'remove'; entity: Entity; traits: (Trait | RelationPair)[] }
+    | { type: 'exclusive'; entity: Entity; traits: RelationPair[] };
+
+type Buffer = { commands: Command[]; spawned: Set<Entity> };
+export type DeferredState = { buffers: Buffer[]; flushing: boolean };
+
+function state(world: World): DeferredState {
+    return (world[$internal].deferredState ??= { buffers: [{ commands: [], spawned: new Set() }], flushing: false });
+}
+function current(world: World) {
+    const buffers = state(world).buffers;
+    return buffers[buffers.length - 1]!;
+}
+export function hasDeferredCommandsFor(world: World, entity: Entity) {
+    return state(world).buffers.some((buffer) => buffer.commands.some((command) => command.entity === entity));
+}
+export function flushDeferredForEntity(world: World, entity: Entity) {
+    if (!state(world).flushing && hasDeferredCommandsFor(world, entity)) flushDeferred(world);
+}
+export function enterDeferredScope(world: World) {
+    state(world).buffers.push({ commands: [], spawned: new Set() });
+}
+export function exitDeferredScope(world: World) {
+    flushDeferred(world);
+    state(world).buffers.pop();
+}
+
+export function createDeferredWorld(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            const entity = allocateEntity(world[$internal].entityIndex);
+            const buffer = current(world);
+            buffer.spawned.add(entity);
+            buffer.commands.push({ type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { current(world).commands.push({ type: 'destroy', entity }); },
+        add(entity, ...traits) { current(world).commands.push({ type: 'add', entity, traits }); },
+        remove(entity, ...traits) { current(world).commands.push({ type: 'remove', entity, traits }); },
+        addExclusive(entity, ...traits) { current(world).commands.push({ type: 'exclusive', entity, traits }); },
+        flush() { flushDeferred(world); },
+    };
+}
+
+/** Applies the active scope only; outer scopes deliberately remain deferred. */
+export function flushDeferred(world: World) {
+    const deferred = state(world);
+    if (deferred.flushing) return;
+    const buffer = current(world);
+    if (!buffer.commands.length) return;
+    deferred.flushing = true;
+    try {
+        // A reserved spawn that is destroyed in its own batch never becomes observable.
+        const nullified = new Set<Entity>();
+        for (const command of buffer.commands) {
+            if (command.type === 'destroy' && buffer.spawned.has(command.entity)) nullified.add(command.entity);
+        }
+        for (const entity of nullified) releaseEntity(world[$internal].entityIndex, entity);
+
+        for (const command of buffer.commands) {
+            if (nullified.has(command.entity)) continue;
+            if (command.type === 'spawn') {
+                initializeDeferredEntity(world, command.entity, ...command.traits);
+                continue;
+            }
+            if (command.entity === world[$internal].worldEntity && command.type === 'destroy') {
+                throw new Error('Koota: The world entity cannot be destroyed by a deferred command.');
+            }
+            // A prior command or an auto-destroy cascade may have killed it.
+            if (!world.has(command.entity)) continue;
+            if (command.type === 'destroy') {
+                destroyEntity(world, command.entity);
+            } else if (command.type === 'add') {
+                addTrait(world, command.entity, ...command.traits);
+            } else if (command.type === 'remove') {
+                removeTrait(world, command.entity, ...command.traits);
+            } else {
+                for (const pair of command.traits) {
+                    if (!isRelationPair(pair)) continue;
+                    const relation = pair[$internal].relation;
+                    // '*' means clear this relation; otherwise replace all current pairs with this one.
+                    removeTrait(world, command.entity, relation('*'));
+                    if (pair[$internal].target !== '*') addTrait(world, command.entity, pair);
+                }
+            }
+        }
+    } finally {
+        buffer.commands.length = 0;
+        buffer.spawned.clear();
+        deferred.flushing = false;
+    }
+}
+
+/** A lightweight overlay for entity.has while commands are queued. */
+export function deferredHas(world: World, entity: Entity, trait: Trait | RelationPair): boolean | undefined {
+    const commands = state(world).buffers.flatMap((buffer) => buffer.commands).filter((c) => c.entity === entity);
+    if (!commands.length) return undefined;
+    let value = isRelationPair(trait)
+        ? entity.has(trait)
+        : hasTrait(world, entity, trait as Trait);
+    for (const command of commands) {
+        if (command.type === 'destroy') return false;
+        const configs = command.type === 'add' || command.type === 'spawn' ? command.traits : [];
+        if (command.type === 'remove') {
+            if (command.traits.includes(trait as any)) value = false;
+        } else if (command.type === 'exclusive' && isRelationPair(trait)) {
+            const relation = trait[$internal].relation;
+            for (const pair of command.traits) if (pair[$internal].relation === relation) value = pair === trait || pair[$internal].target === trait[$internal].target;
+        } else {
+            for (const config of configs) if (config === trait || (Array.isArray(config) && config[0] === trait)) value = true;
+        }
+    }
+    return value;
+}
+
+export function deferredGet(world: World, entity: Entity, trait: Trait | RelationPair): any {
+    const commands = state(world).buffers.flatMap((buffer) => buffer.commands).filter((c) => c.entity === entity);
+    if (!commands.length) return undefined;
+    let value = getTrait(world, entity, trait);
+    for (const command of commands) {
+        if (command.type === 'destroy') return undefined;
+        if (command.type === 'remove' && command.traits.includes(trait as any)) value = undefined;
+        const configs = command.type === 'add' || command.type === 'spawn' ? command.traits : [];
+        for (const config of configs) {
+            if (config === trait) value = value ?? {};
+            else if (Array.isArray(config) && config[0] === trait) value = { ...(value ?? {}), ...config[1] };
+        }
+    }
+    return value;
+}
