+type PairState = { entity: Entity; target?: Entity; value: any };
+type StateSnapshot = Map<Trait, Map<string, PairState>>;
+type Silenced = { set: Set<any>; values: any[] }[];
+
+function snapshot(world: World): StateSnapshot {
+    const result: StateSnapshot = new Map();
+    for (const trait of world.traits) {
+        const entries = new Map<string, PairState>();
+        const relation = trait[$internal].relation;
+        for (const entity of world.entities) {
+            if (!hasTrait(world, entity, trait)) continue;
+            if (relation) {
+                for (const target of getRelationTargets(world, relation, entity)) {
+                    const value = getTrait(world, entity, relation(target));
+                    entries.set(`${entity}:${target}`, { entity, target, value: value && { ...value } });
+                }
+            } else {
+                const value = getTrait(world, entity, trait);
+                entries.set(`${entity}`, { entity, value: value && { ...value } });
+            }
+        }
+        result.set(trait, entries);
+    }
+    return result;
+}
+
+function silenceSubscriptions(world: World): Silenced {
+    const saved: Silenced = [];
+    for (const instance of world[$internal].traitInstances) {
+        if (!instance) continue;
+        for (const set of [instance.addSubscriptions, instance.removeSubscriptions, instance.changeSubscriptions]) {
+            saved.push({ set, values: [...set] });
+            set.clear();
+        }
+    }
+    return saved;
+}
+function restoreSubscriptions(saved: Silenced) {
+    for (const { set, values } of saved) set.add(...values);
+}
+function emitSubscriptionDiff(world: World, before: StateSnapshot) {
+    const after = snapshot(world);
+    const traits = new Set([...before.keys(), ...after.keys()]);
+    for (const trait of traits) {
+        const instance = getTraitInstance(world[$internal].traitInstances, trait);
+        if (!instance) continue;
+        const oldEntries = before.get(trait) ?? new Map();
+        const newEntries = after.get(trait) ?? new Map();
+        for (const [key, entry] of oldEntries) {
+            if (!newEntries.has(key)) for (const sub of instance.removeSubscriptions) sub(entry.entity, entry.target);
+        }
+        for (const [key, entry] of newEntries) {
+            if (!oldEntries.has(key)) {
+                for (const sub of instance.addSubscriptions) sub(entry.entity, entry.target);
+            } else if (!shallowEqual(oldEntries.get(key)!.value, entry.value)) {
+                for (const sub of instance.changeSubscriptions) sub(entry.entity, entry.target);
+            }
+        }
+    }
