/** Applies the active scope only; outer scopes deliberately remain deferred. */
export function flushDeferred(world: World) {
    const deferred = state(world);
    if (deferred.flushing) return;
    const buffer = current(world);
    if (!buffer.commands.length) return;
    deferred.flushing = true;
    try {
        const before = snapshot(world);
        const subscriptions = silenceSubscriptions(world);
        // A reserved spawn that is destroyed in its own batch never becomes observable.
        const nullified = new Set<Entity>();
        for (const command of buffer.commands) {
            if (command.type === 'destroy' && buffer.spawned.has(command.entity)) nullified.add(command.entity);
        }
        for (const entity of nullified) releaseEntity(world[$internal].entityIndex, entity);

        for (const command of buffer.commands) {
            if (nullified.has(command.entity)) continue;
            if (command.type === 'spawn') {
                initializeDeferredEntity(world, command.entity, ...command.traits);
                continue;
            }
            if (command.entity === world[$internal].worldEntity && command.type === 'destroy') {
                throw new Error('Koota: The world entity cannot be destroyed by a deferred command.');
            }
            // A prior command or an auto-destroy cascade may have killed it.
            if (!world.has(command.entity)) continue;
            if (command.type === 'destroy') {
                destroyEntity(world, command.entity);
            } else if (command.type === 'add') {
                for (const config of command.traits) {
                    addTrait(world, command.entity, config);
                    if (Array.isArray(config)) setTrait(world, command.entity, config[0], config[1]);
                    else if (isRelationPair(config) && hasRelationPair(world, command.entity, config)) {
                        const params = config[$internal].params;
                        if (params) setTrait(world, command.entity, config, params);
                    }
                }
            } else if (command.type === 'remove') {
                removeTrait(world, command.entity, ...command.traits);
            } else {
                for (const pair of command.traits) {
                    if (!isRelationPair(pair)) continue;
                    const relation = pair[$internal].relation;
                    // '*' means clear this relation; otherwise replace all current pairs with this one.
                    removeTrait(world, command.entity, relation('*'));
                    if (pair[$internal].target !== '*') addTrait(world, command.entity, pair);
                }
            }
        }
        restoreSubscriptions(subscriptions);
        emitSubscriptionDiff(world, before);
    } finally {
        buffer.commands.length = 0;
        buffer.spawned.clear();
        deferred.flushing = false;
    }
}

